    function togglePanel() {
        var panel = document.getElementById('bili-tracker-panel');
        var overlay = document.getElementById('bili-tracker-overlay');
        if (!panel || !overlay) {
            createPanel();
            return;
        }
        var isOpen = panel.style.left === '0px';
        if (isOpen) {
            panel.style.left = '-1100px';
            overlay.style.opacity = '0';
            setTimeout(function() { overlay.style.display = 'none'; }, 300);
        } else {
            panel.style.left = '0px';
            overlay.style.display = 'block';
            setTimeout(function() { overlay.style.opacity = '1'; }, 10);
            var syncBtn = document.getElementById('bt-sync-btn');
            if (syncBtn && syncBtn.disabled) {
                syncBtn.textContent = '同步最新数据';
                syncBtn.disabled = false;
            }
            var refreshBtn = document.getElementById('bt-refresh-list-btn');
            if (refreshBtn && refreshBtn.disabled) {
                refreshBtn.textContent = '刷新列表';
                refreshBtn.disabled = false;
            }
        }
    }

